head.script:
// 전역변수
scwin.login = $c.data.getMemInfo();
scwin.privAdmin = scwin.login.privAdmin;
scwin.vUserHomeClsCd = scwin.login.userHomeClsCd;
scwin.vLoginCoCd = scwin.login.coCd;
scwin.vLoginCoClsCd = scwin.login.coClsCd;

scwin.isSubCompany;
scwin.isFirst = true;

// hidden 컴포넌트
scwin.txtCoClsCd;


scwin.onpageload = function () {
    const codeOptions = [
        { grpCd: "FM111", compID: "acb_intrlns" },
    ];
    $c.data.setCommonCode(codeOptions);

};

scwin.onUdcCompleted = function () {

    // scwin.f_HeaderCreate();
    scwin.f_FieldClear();
    scwin.f_setCompanyInfo();

    // 현재 월로 셋팅한다.
    ica_stdYm.setValue(WebSquare.date.getCurrentServerDate());
    ica_stdYm.focus();


};

//-------------------------------------------------------------------------
// 조회 조건 입력창에 있는 내용을 모두 지운다.
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {

    // 조회 조건의 필드 내용을 지운다.
    $c.gus.cfInitObjects(table1, null);
    // 현재 월로 셋팅한다.
    ica_stdYm.setValue(WebSquare.date.getCurrentServerDate());

    ed_acctDeptCd.setValue('00000');
    ed_acctDeptNm.setValue('전사');
}

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function () {

    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }

    ed_coCd.setValue(scwin.vLoginCoCd)
    scwin.f_PopUpCompanyInfo('T');
}

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = function (pWinCloseTF) {

    udc_companyInfo.cfCommonPopUp(scwin.udc_companyInfo_callBackFunc
        , ed_coCd.getValue(), ed_coNm.getValue()
        , pWinCloseTF, null, null, null, null
        , null, null, null, null, null);
}

scwin.udc_companyInfo_callBackFunc = function (rtnList) {

    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_coCd.setValue(rtnList[0]);
        ed_coNm.setValue(rtnList[5]);
        ed_coCd.options.hidVal = rtnList[0];
        scwin.txtCoClsCd = rtnList[1];
    } else {
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        ed_coCd.options.hidVal = "";
        scwin.txtCoClsCd = "";
    }

    if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {  	// 자회사 회계 시스템 
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }

    if (scwin.isFirst == true) {

        if ('T' == scwin.privAdmin || !scwin.isSubCompany) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
            $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_company]);
        }
        else {
            $c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company]);
        }

        scwin.isFirst = false;
    }
};

